def solution(limit=50000000):
    p_limit = int(limit**0.5) + 1
    sieve = [True] * p_limit
    primes = []
    for p in range(2, p_limit):
        if sieve[p]:
            primes.append(p)
            for i in range(p*p, p_limit, p): sieve[i] = False
    results = set()
    for p1 in primes:
        s1 = p1**2
        if s1 >= limit: break
        for p2 in primes:
            s2 = s1 + p2**3
            if s2 >= limit: break
            for p3 in primes:
                s3 = s2 + p3**4
                if s3 >= limit: break
                results.add(s3)
    return len(results)
